mapper.select:
SELECT SUBSTRING(TF003, 1, ${type}) AS warehousingDate, MD002 AS workShop, SUM(CAST(TG011 AS DECIMAL(10, 2))) AS warehousingQuantity FROM MOCTF LEFT JOIN MOCTG ON TF001 = TG001 AND TF002 = TG002 LEFT JOIN CMSMD ON TF004 = MD003 AND TF011 = MD001
TF006 = 'Y'
AND MD002 = #{workShop}
GROUP BY SUBSTRING(TF003, 1, ${type}), CMSMD.MD002 ORDER BY SUBSTRING(TF003, 1, ${type}) DESC, CMSMD.MD002 ASC;
